import * as t from "io-ts";
import { BaseStakeIntent } from "./baseStakeIntent";
import { SubstrateAccountBaseBuildOptions } from "./substrateAccountBaseBuildOptions";

/**
 * @title Tao Staking Base Intent
 */
export const TaoStakingBaseIntent = t.intersection([
  BaseStakeIntent,
  SubstrateAccountBaseBuildOptions,
  t.type({
    hotkey: t.string,
    netuid: t.string,
  }),
]);

export type TaoStakingBaseIntent = t.TypeOf<typeof TaoStakingBaseIntent>;
